                                assert_sets_equal!(abstractify_seq_of_cpackets_to_set_of_sht_packets(sent_packets@),
                                                   extract_packets_from_lsht_packets(
                                                       abstractify_outbound_packets_to_seq_of_lsht_packets(
                                                           sent_packets@)));
                                assert_sets_equal!(abstractify_seq_of_cpackets_to_set_of_sht_packets(sent_packets@),
