                                                                  pkt.msg.arrow_Message_m(),
                                                                  sm,
                                                                  Message::Reply{key: *k,
                                                                                 value: optional_value_view(*ov)},
                                                                  Set::<Packet>::empty(), true));
                                assert (next_set_request(old(self)@, self@, cpacket@,
                                                         abstractify_seq_of_cpackets_to_set_of_sht_packets(
