                                        assert (next_set_request_complete(
                                                    old(self)@, self@, pkt.src,
                                                    pkt.msg.arrow_Message_seqno(),
                                                    m@, sm@, mm@,
                                                    abstractify_seq_of_cpackets_to_set_of_sht_packets(sent_packets@),
